#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int tr[N],a[N],b[N],n,tmp[N];
void update(int x,int y)
{
	for(int i=x;i<=n;i+=(i&(-i)))
	{
		if(tr[i]>=y) return ;
		tr[i]=y;
	}
}
int query(int x)
{
	int ans=0;
	for(int i=x;i>0;i-=(i&(-i)))
	{
		ans=max(ans,tr[i]);
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=n;i++)
	{
		int x;
		cin>>x;
		b[x]=i;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=max(1,a[i]-4);j<=min(n,a[i]+4);j++)
		{
			tmp[j]=query(b[j]-1);
		}
		for(int j=max(1,a[i]-4);j<=min(n,a[i]+4);j++)
		{
			update(b[j],tmp[j]+1);
		}
	}
	cout<<query(n);
	return 0;
}
